    parser.add_argument("--metadata-max-age-ms", type=int, default=300000)
    parser.add_argument(
        "--security-protocol",
        default="PLAINTEXT",
        choices=["PLAINTEXT", "SSL", "SASL_PLAINTEXT", "SASL_SSL"],
    )
    parser.add_argument("--sasl-mechanism", default="PLAIN")
    parser.add_argument("--sasl-plain-username")
    parser.add_argument("--sasl-plain-password")
    parser.add_argument("--ssl-cafile")
    parser.add_argument("--ssl-certfile")
    parser.add_argument("--ssl-keyfile")
    parser.add_argument("--ssl-password")
    parser.add_argument(
        "--ssl-check-hostname",
        dest="ssl_check_hostname",
        action="store_true",
        default=None,
    )
    parser.add_argument(
        "--no-ssl-check-hostname",
        dest="ssl_check_hostname",
        action="store_false",
    )
    parser.add_argument("--operation-timeout-ms", type=int, default=30000)


